function Scene() {
  var useState = React.useState;
  var useRef = React.useRef;
  var useMemo = React.useMemo;
  var useCallback = React.useCallback;
  var useEffect = React.useEffect;
  var useFrame = helpers.useFrame;
  var Html = helpers.Html;
  var ScreenOverlay = helpers.ScreenOverlay;
  var InfoPoint = helpers.InfoPoint;
  var ce = React.createElement;

  // Params
  var cVal = runtimeState.params.cValue !== undefined ? runtimeState.params.cValue : 1;
  var kernelMix = runtimeState.params.kernelMix !== undefined ? runtimeState.params.kernelMix : 0;
  var rbfGamma = runtimeState.params.rbfGamma !== undefined ? runtimeState.params.rbfGamma : 1;
  var pointCount = runtimeState.params.pointCount !== undefined ? runtimeState.params.pointCount : 10;
  var noise = runtimeState.params.noise !== undefined ? runtimeState.params.noise : 0.4;
  var stepIndex = runtimeState.params.stepIndex !== undefined ? runtimeState.params.stepIndex : 0;

  // Seed-based random for reproducibility
  var [seed, setSeed] = useState(42);
  function seededRandom(s) {
    var x = Math.sin(s * 9301 + 49297) * 233280;
    return x - Math.floor(x);
  }

  // Generate points
  var points = useMemo(function() {
    var pts = [];
    var n = Math.round(pointCount);
    for (var i = 0; i < n; i++) {
      var r1 = seededRandom(seed + i * 3);
      var r2 = seededRandom(seed + i * 3 + 1);
      pts.push({
        x: -2.5 + r1 * 2 + (seededRandom(seed + i * 7) - 0.5) * noise * 2,
        y: -1 + r2 * 2 + (seededRandom(seed + i * 11) - 0.5) * noise * 2,
        label: 1,
        id: i
      });
    }
    for (var j = 0; j < n; j++) {
      var r3 = seededRandom(seed + (j + n) * 3);
      var r4 = seededRandom(seed + (j + n) * 3 + 1);
      pts.push({
        x: 0.5 + r3 * 2 + (seededRandom(seed + (j + n) * 7) - 0.5) * noise * 2,
        y: -1 + r4 * 2 + (seededRandom(seed + (j + n) * 11) - 0.5) * noise * 2,
        label: -1,
        id: j + n
      });
    }
    return pts;
  }, [seed, pointCount, noise]);

  // Simple linear SVM using gradient descent
  var svmResult = useMemo(function() {
    var w0 = 1, w1 = 0, b = 0;
    var C = cVal;
    var lr = 0.01;
    var epochs = 800;
    var pts = points;
    if (pts.length < 2) return { w: [1, 0], b: 0, sv: [], margin: 1 };
    for (var ep = 0; ep < epochs; ep++) {
      var dw0 = w0, dw1 = w1, db = 0;
      for (var i = 0; i < pts.length; i++) {
        var p = pts[i];
        var margin = p.label * (w0 * p.x + w1 * p.y + b);
        if (margin < 1) {
          dw0 -= C * p.label * p.x;
          dw1 -= C * p.label * p.y;
          db -= C * p.label;
        }
      }
      w0 -= lr * dw0;
      w1 -= lr * dw1;
      b -= lr * db;
    }
    var norm = Math.sqrt(w0 * w0 + w1 * w1);
    if (norm < 0.001) norm = 0.001;
    var marginWidth = 2 / norm;
    var svs = [];
    for (var j = 0; j < pts.length; j++) {
      var pp = pts[j];
      var val = pp.label * (w0 * pp.x + w1 * pp.y + b);
      if (val < 1.05) {
        svs.push(pp.id);
      }
    }
    return { w: [w0, w1], b: b, sv: svs, margin: marginWidth, norm: norm };
  }, [points, cVal]);

  // RBF kernel decision boundary (grid evaluation)
  var rbfGrid = useMemo(function() {
    if (kernelMix < 0.5) return null;
    var gamma = rbfGamma;
    var C = cVal;
    var pts = points;
    var gridSize = 30;
    var xMin = -4, xMax = 4, yMin = -3, yMax = 3;
    var grid = [];
    // Simple RBF classification using weighted nearest neighbor approach
    for (var gi = 0; gi < gridSize; gi++) {
      for (var gj = 0; gj < gridSize; gj++) {
        var gx = xMin + (xMax - xMin) * gi / (gridSize - 1);
        var gy = yMin + (yMax - yMin) * gj / (gridSize - 1);
        var score = 0;
        var totalW = 0;
        for (var k = 0; k < pts.length; k++) {
          var dx = gx - pts[k].x;
          var dy = gy - pts[k].y;
          var dist2 = dx * dx + dy * dy;
          var wt = Math.exp(-gamma * dist2);
          score += pts[k].label * wt;
          totalW += wt;
        }
        if (totalW > 0) score /= totalW;
        grid.push({ x: gx, y: gy, val: score });
      }
    }
    return { grid: grid, gridSize: gridSize, xMin: xMin, xMax: xMax, yMin: yMin, yMax: yMax };
  }, [points, rbfGamma, cVal, kernelMix]);

  // Dragging state
  var [dragId, setDragId] = useState(null);
  var [draggedOffsets, setDraggedOffsets] = useState({});
  var [hovered, setHovered] = useState(null);
  var [animTime, setAnimTime] = useState(0);

  var groupRef = useRef();

  useFrame(function(state, delta) {
    setAnimTime(function(t) { return t + delta; });
  });

  // Colors
  var classAColor = "#2563eb";
  var classBColor = "#ef4444";
  var boundaryColor = "#111827";
  var marginColor = "#10b981";
  var highlightColor = "#f59e0b";

  // Panel styling
  var panelBg = "rgba(250, 245, 235, 0.92)";
  var panelBorder = "rgba(0, 0, 0, 0.1)";
  var textPrimary = "#1e293b";
  var textMuted = "#64748b";

  // Steps
  var steps = [
    { instruction: "Set Kernel Mode to Linear (0). Drag a blue point closer to the red cluster until it nears the margin.", concept: "Closest points start to control the solution; the boundary reacts strongly to near-boundary points.", condition: function() { return kernelMix < 0.5 && noise >= 0.2; } },
    { instruction: "Identify the highlighted points: the ones with golden rings are Support Vectors.", concept: "Support vectors are the only points that directly define the max-margin boundary; far-away points matter less.", condition: function() { return kernelMix < 0.5 && cVal >= 0.5 && cVal <= 2; } },
    { instruction: "Increase C to a large value (20-50). Observe margin width and which points become support vectors.", concept: "Larger C penalizes violations more, often shrinking the margin and forcing the boundary to fit training points strictly.", condition: function() { return cVal >= 20; } },
    { instruction: "Decrease C to a small value (0.05-0.2). Observe a wider margin and more tolerance for margin violations.", concept: "Smaller C allows more slack (soft margin), widening the margin and prioritizing general separation over perfect fit.", condition: function() { return cVal <= 0.2; } },
    { instruction: "Switch Kernel Mode to RBF (1) and adjust gamma from low to high. Watch the boundary change.", concept: "Kernels create non-linear boundaries; gamma controls how local the influence is (higher = more complex boundary).", condition: function() { return kernelMix >= 0.5 && rbfGamma >= 5; } }
  ];

  var currentStep = steps[stepIndex] || steps[0];
  var conditionMet = currentStep.condition();

  // Build 3D scene elements
  var children = [];

  // Ambient + directional light
  children.push(ce("ambientLight", { key: "amb", intensity: 0.8 }));
  children.push(ce("directionalLight", { key: "dir", position: [5, 10, 5], intensity: 0.6 }));

  // Grid plane
  children.push(ce("mesh", { key: "plane", rotation: [-Math.PI / 2, 0, 0], position: [0, -0.05, 0] },
    ce("planeGeometry", { args: [10, 8] }),
    ce("meshStandardMaterial", { color: "#f8f5f0", transparent: true, opacity: 0.9 })
  ));

  // Grid lines
  for (var gx = -5; gx <= 5; gx++) {
    var linePositions = new Float32Array([gx, 0, -4, gx, 0, 4]);
    children.push(ce("line", { key: "gx" + gx },
      ce("bufferGeometry", null,
        ce("bufferAttribute", { attach: "attributes-position", count: 2, array: linePositions, itemSize: 3 })
      ),
      ce("lineBasicMaterial", { color: "#d1d5db", transparent: true, opacity: 0.5 })
    ));
  }
  for (var gy = -4; gy <= 4; gy++) {
    var linePositions2 = new Float32Array([-5, 0, gy, 5, 0, gy]);
    children.push(ce("line", { key: "gy" + gy },
      ce("bufferGeometry", null,
        ce("bufferAttribute", { attach: "attributes-position", count: 2, array: linePositions2, itemSize: 3 })
      ),
      ce("lineBasicMaterial", { color: "#d1d5db", transparent: true, opacity: 0.5 })
    ));
  }

  // Decision boundary line (linear)
  if (kernelMix < 0.5) {
    var w = svmResult.w;
    var bVal = svmResult.b;
    var norm = svmResult.norm;
    // Draw line: w0*x + w1*y + b = 0 => y = -(w0*x + b)/w1
    // We draw in XZ plane (y=0.01)
    var linePoints = [];
    var marginPlusPoints = [];
    var marginMinusPoints = [];
    for (var t = -5; t <= 5; t += 0.2) {
      if (Math.abs(w[1]) > 0.001) {
        var yy = -(w[0] * t + bVal) / w[1];
        var yyPlus = -(w[0] * t + bVal - 1) / w[1];
        var yyMinus = -(w[0] * t + bVal + 1) / w[1];
        linePoints.push(t, 0.02, yy);
        marginPlusPoints.push(t, 0.01, yyPlus);
        marginMinusPoints.push(t, 0.01, yyMinus);
      } else if (Math.abs(w[0]) > 0.001) {
        var xx = -bVal / w[0];
        linePoints.push(xx, 0.02, t);
        marginPlusPoints.push(xx + 1 / w[0], 0.01, t);
        marginMinusPoints.push(xx - 1 / w[0], 0.01, t);
      }
    }
    if (linePoints.length > 0) {
      var lpArr = new Float32Array(linePoints);
      children.push(ce("line", { key: "boundary" },
        ce("bufferGeometry", null,
          ce("bufferAttribute", { attach: "attributes-position", count: lpArr.length / 3, array: lpArr, itemSize: 3 })
        ),
        ce("lineBasicMaterial", { color: boundaryColor, linewidth: 2 })
      ));
    }
    if (marginPlusPoints.length > 0) {
      var mpArr = new Float32Array(marginPlusPoints);
      children.push(ce("line", { key: "marginPlus" },
        ce("bufferGeometry", null,
          ce("bufferAttribute", { attach: "attributes-position", count: mpArr.length / 3, array: mpArr, itemSize: 3 })
        ),
        ce("lineBasicMaterial", { color: marginColor, transparent: true, opacity: 0.7 })
      ));
    }
    if (marginMinusPoints.length > 0) {
      var mmArr = new Float32Array(marginMinusPoints);
      children.push(ce("line", { key: "marginMinus" },
        ce("bufferGeometry", null,
          ce("bufferAttribute", { attach: "attributes-position", count: mmArr.length / 3, array: mmArr, itemSize: 3 })
        ),
        ce("lineBasicMaterial", { color: marginColor, transparent: true, opacity: 0.7 })
      ));
    }

    // Margin fill (semi-transparent plane between margin lines)
    if (Math.abs(w[1]) > 0.001) {
      var angle = Math.atan2(-w[0], w[1]);
      var mWidth = svmResult.margin;
      var cx = 0;
      var cy = -(w[0] * 0 + bVal) / w[1];
      children.push(ce("mesh", { key: "marginFill", position: [cx, 0.005, cy], rotation: [-Math.PI / 2, 0, angle] },
        ce("planeGeometry", { args: [10, Math.min(mWidth, 6)] }),
        ce("meshBasicMaterial", { color: marginColor, transparent: true, opacity: 0.08, side: 2 })
      ));
    }
  }

  // RBF boundary visualization
  if (kernelMix >= 0.5 && rbfGrid) {
    var gs = rbfGrid.gridSize;
    var grid = rbfGrid.grid;
    // Draw colored squares for the decision regions
    for (var gi2 = 0; gi2 < gs - 1; gi2++) {
      for (var gj2 = 0; gj2 < gs - 1; gj2++) {
        var idx = gi2 * gs + gj2;
        var v = grid[idx].val;
        var gx2 = grid[idx].x;
        var gy2 = grid[idx].y;
        var dx2 = (rbfGrid.xMax - rbfGrid.xMin) / (gs - 1);
        var dy2 = (rbfGrid.yMax - rbfGrid.yMin) / (gs - 1);
        var col = v > 0 ? classAColor : classBColor;
        var op = Math.min(Math.abs(v) * 0.25, 0.15);
        children.push(ce("mesh", { key: "rbf" + gi2 + "_" + gj2, position: [gx2 + dx2 / 2, 0.003, gy2 + dy2 / 2], rotation: [-Math.PI / 2, 0, 0] },
          ce("planeGeometry", { args: [dx2, dy2] }),
          ce("meshBasicMaterial", { color: col, transparent: true, opacity: op, side: 2 })
        ));
      }
    }
    // Draw boundary contour (where val crosses 0)
    var contourPts = [];
    for (var ci = 0; ci < gs - 1; ci++) {
      for (var cj = 0; cj < gs - 1; cj++) {
        var i1 = ci * gs + cj;
        var i2 = ci * gs + cj + 1;
        var i3 = (ci + 1) * gs + cj;
        if (grid[i1].val * grid[i2].val < 0) {
          var tt = grid[i1].val / (grid[i1].val - grid[i2].val);
          contourPts.push(grid[i1].x + tt * (grid[i2].x - grid[i1].x), 0.03, grid[i1].y + tt * (grid[i2].y - grid[i1].y));
        }
        if (grid[i1].val * grid[i3].val < 0) {
          var tt2 = grid[i1].val / (grid[i1].val - grid[i3].val);
          contourPts.push(grid[i1].x + tt2 * (grid[i3].x - grid[i1].x), 0.03, grid[i1].y + tt2 * (grid[i3].y - grid[i1].y));
        }
      }
    }
    // Render contour as points
    if (contourPts.length > 0) {
      var cArr = new Float32Array(contourPts);
      children.push(ce("points", { key: "rbfContour" },
        ce("bufferGeometry", null,
          ce("bufferAttribute", { attach: "attributes-position", count: cArr.length / 3, array: cArr, itemSize: 3 })
        ),
        ce("pointsMaterial", { size: 0.12, color: boundaryColor, sizeAttenuation: true })
      ));
    }
  }

  // Data points
  for (var pi = 0; pi < points.length; pi++) {
    var pt = points[pi];
    var offset = draggedOffsets[pt.id] || { x: 0, y: 0 };
    var px = pt.x + offset.x;
    var pz = pt.y + offset.y;
    var isClass1 = pt.label === 1;
    var color = isClass1 ? classAColor : classBColor;
    var isSV = svmResult.sv.indexOf(pt.id) !== -1;
    var isHov = hovered === pt.id;
    var radius = 0.12;

    // Support vector ring
    if (isSV) {
      children.push(ce("mesh", { key: "svring" + pi, position: [px, 0.05, pz], rotation: [-Math.PI / 2, 0, 0] },
        ce("ringGeometry", { args: [0.16, 0.22, 24] }),
        ce("meshBasicMaterial", { color: highlightColor, side: 2 })
      ));
    }

    // Point sphere
    var ptChildren = [];
    ptChildren.push(ce("sphereGeometry", { key: "sg", args: [radius, 16, 16] }));
    ptChildren.push(ce("meshStandardMaterial", {
      key: "sm",
      color: color,
      emissive: isHov ? highlightColor : (isSV ? highlightColor : color),
      emissiveIntensity: isHov ? 0.6 : (isSV ? 0.3 : 0.1)
    }));

    children.push(ce("mesh", {
      key: "pt" + pi,
      position: [px, radius + 0.02, pz],
      onPointerOver: (function(id) { return function(e) { e.stopPropagation(); setHovered(id); }; })(pt.id),
      onPointerOut: function(e) { e.stopPropagation(); setHovered(null); },
      onClick: (function(id) { return function(e) { e.stopPropagation(); }; })(pt.id)
    }, ptChildren[0], ptChildren[1]));
  }

  // Info Points
  if (kernelMix < 0.5 && Math.abs(svmResult.w[1]) > 0.001) {
    var bpX = 0;
    var bpZ = -(svmResult.w[0] * 0 + svmResult.b) / svmResult.w[1];
    children.push(ce(InfoPoint, {
      key: "ip-hyper",
      label: "HYPERPLANE",
      explanation: "The decision boundary that separates the classes. For linear SVMs, it is the line that maximizes the margin between classes.",
      position: [bpX, 0.5, bpZ],
      color: boundaryColor
    }));

    children.push(ce(InfoPoint, {
      key: "ip-margin",
      label: "MARGIN",
      explanation: "The safety buffer around the boundary. SVM tries to make this buffer as wide as possible while still separating the data.",
      position: [bpX + 1.5, 0.4, bpZ],
      color: marginColor
    }));
  }

  // Find a support vector position for info point
  var svPt = null;
  for (var si = 0; si < points.length; si++) {
    if (svmResult.sv.indexOf(points[si].id) !== -1) {
      svPt = points[si];
      break;
    }
  }
  if (svPt) {
    var svo = draggedOffsets[svPt.id] || { x: 0, y: 0 };
    children.push(ce(InfoPoint, {
      key: "ip-sv",
      label: "SUPPORT VECTORS",
      explanation: "Points closest to the boundary that pin the margin and determine where the boundary ends up. Moving them moves the boundary the most.",
      position: [svPt.x + svo.x, 0.8, svPt.y + svo.y],
      color: highlightColor
    }));
  }

  children.push(ce(InfoPoint, {
    key: "ip-slack",
    label: "SLACK (SOFT MARGIN)",
    explanation: "When data isn't perfectly separable, some points are allowed inside the margin or misclassified. The penalty is controlled by C.",
    position: [-1, 0.6, 2],
    color: highlightColor
  }));

  if (kernelMix >= 0.5) {
    children.push(ce(InfoPoint, {
      key: "ip-kernel",
      label: "KERNEL (RBF)",
      explanation: "A kernel allows a curved boundary by comparing points through a similarity function. RBF can create flexible, non-linear decision regions.",
      position: [2, 0.7, 0],
      color: boundaryColor
    }));
  }

  children.push(ce(InfoPoint, {
    key: "ip-classes",
    label: "CLASS LABELS",
    explanation: "Blue and red points represent two categories the SVM is trying to separate.",
    position: [-3, 0.5, -2],
    color: classAColor
  }));

  // Axis labels
  children.push(ce(Html, { key: "xlabel", position: [4.5, 0.1, 0], center: true },
    ce("div", { style: { color: textMuted, fontSize: 11, fontFamily: "system-ui", letterSpacing: "0.15em", textTransform: "uppercase", pointerEvents: "none" } }, "X\u2081")
  ));
  children.push(ce(Html, { key: "ylabel", position: [0, 0.1, 3.5], center: true },
    ce("div", { style: { color: textMuted, fontSize: 11, fontFamily: "system-ui", letterSpacing: "0.15em", textTransform: "uppercase", pointerEvents: "none" } }, "X\u2082")
  ));

  // Screen Overlay
  var overlay = ce(ScreenOverlay, { key: "overlay" },
    // Control Panel - top left
    ce("div", {
      style: {
        position: "absolute", top: 16, left: 16, background: panelBg, backdropFilter: "blur(12px)",
        border: "1px solid " + panelBorder, borderRadius: 12, padding: 18, minWidth: 240, pointerEvents: "auto"
      }
    },
      ce("div", { style: { fontSize: 10, textTransform: "uppercase", letterSpacing: "0.22em", color: textPrimary, fontFamily: "system-ui", fontWeight: 700, marginBottom: 14 } }, "SVM Controls"),
      // C slider
      ce("div", { style: { marginBottom: 10 } },
        ce("div", { style: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 } },
          ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Softness (C)"),
          ce("span", { style: { fontSize: 12, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, cVal.toFixed(2))
        ),
        ce("input", { type: "range", min: 0.05, max: 50, step: 0.05, value: cVal, style: { width: "100%", accentColor: classAColor }, onChange: function(e) { runtimeState.params.cValue = parseFloat(e.target.value); } })
      ),
      // Kernel slider
      ce("div", { style: { marginBottom: 10 } },
        ce("div", { style: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 } },
          ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Kernel Mode"),
          ce("span", { style: { fontSize: 12, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, kernelMix < 0.5 ? "Linear" : "RBF")
        ),
        ce("input", { type: "range", min: 0, max: 1, step: 1, value: kernelMix, style: { width: "100%", accentColor: classAColor }, onChange: function(e) { runtimeState.params.kernelMix = parseFloat(e.target.value); } })
      ),
      // Gamma slider
      kernelMix >= 0.5 ? ce("div", { style: { marginBottom: 10 } },
        ce("div", { style: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 } },
          ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "RBF \u03B3"),
          ce("span", { style: { fontSize: 12, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, rbfGamma.toFixed(1))
        ),
        ce("input", { type: "range", min: 0.1, max: 10, step: 0.1, value: rbfGamma, style: { width: "100%", accentColor: classAColor }, onChange: function(e) { runtimeState.params.rbfGamma = parseFloat(e.target.value); } })
      ) : null,
      // Points slider
      ce("div", { style: { marginBottom: 10 } },
        ce("div", { style: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 } },
          ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Points/Class"),
          ce("span", { style: { fontSize: 12, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, Math.round(pointCount))
        ),
        ce("input", { type: "range", min: 3, max: 30, step: 1, value: pointCount, style: { width: "100%", accentColor: classAColor }, onChange: function(e) { runtimeState.params.pointCount = parseFloat(e.target.value); } })
      ),
      // Noise slider
      ce("div", { style: { marginBottom: 10 } },
        ce("div", { style: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 } },
          ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Overlap (Noise)"),
          ce("span", { style: { fontSize: 12, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, noise.toFixed(2))
        ),
        ce("input", { type: "range", min: 0, max: 2, step: 0.05, value: noise, style: { width: "100%", accentColor: classAColor }, onChange: function(e) { runtimeState.params.noise = parseFloat(e.target.value); } })
      ),
      // Regenerate button
      ce("button", {
        style: {
          width: "100%", padding: "8px 14px", borderRadius: 6, border: "1px solid " + panelBorder,
          background: "rgba(37, 99, 235, 0.1)", color: textPrimary, fontSize: 11, textTransform: "uppercase",
          letterSpacing: "0.1em", cursor: "pointer", fontFamily: "system-ui", fontWeight: 600
        },
        onClick: function() { setSeed(function(s) { return s + 1; }); setDraggedOffsets({}); }
      }, "\u21BB Regenerate Points")
    ),
    // Legend - top right area below steps
    ce("div", {
      style: {
        position: "absolute", top: 16, left: "50%", transform: "translateX(-50%)", background: panelBg, backdropFilter: "blur(12px)",
        border: "1px solid " + panelBorder, borderRadius: 12, padding: "12px 20px", pointerEvents: "auto", display: "flex", gap: 20, alignItems: "center"
      }
    },
      ce("div", { style: { display: "flex", alignItems: "center", gap: 6 } },
        ce("div", { style: { width: 12, height: 12, borderRadius: "50%", background: classAColor } }),
        ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textPrimary, fontFamily: "system-ui" } }, "Class A (+1)")
      ),
      ce("div", { style: { display: "flex", alignItems: "center", gap: 6 } },
        ce("div", { style: { width: 12, height: 12, borderRadius: "50%", background: classBColor } }),
        ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textPrimary, fontFamily: "system-ui" } }, "Class B (-1)")
      ),
      ce("div", { style: { display: "flex", alignItems: "center", gap: 6 } },
        ce("div", { style: { width: 12, height: 12, borderRadius: "50%", border: "3px solid " + highlightColor, background: "transparent" } }),
        ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textPrimary, fontFamily: "system-ui" } }, "Support Vector")
      ),
      ce("div", { style: { display: "flex", alignItems: "center", gap: 6 } },
        ce("div", { style: { width: 20, height: 3, background: boundaryColor } }),
        ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textPrimary, fontFamily: "system-ui" } }, "Boundary")
      ),
      ce("div", { style: { display: "flex", alignItems: "center", gap: 6 } },
        ce("div", { style: { width: 20, height: 3, background: marginColor } }),
        ce("span", { style: { fontSize: 11, textTransform: "uppercase", letterSpacing: "0.15em", color: textPrimary, fontFamily: "system-ui" } }, "Margin")
      )
    ),
    // Stats readout
    ce("div", {
      style: {
        position: "absolute", bottom: 16, left: "50%", transform: "translateX(-50%)", background: panelBg, backdropFilter: "blur(12px)",
        border: "1px solid " + panelBorder, borderRadius: 12, padding: "12px 24px", pointerEvents: "auto", display: "flex", gap: 30, alignItems: "center"
      }
    },
      ce("div", { style: { textAlign: "center" } },
        ce("div", { style: { fontSize: 18, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, svmResult.sv.length),
        ce("div", { style: { fontSize: 10, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Support Vectors")
      ),
      ce("div", { style: { textAlign: "center" } },
        ce("div", { style: { fontSize: 18, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, kernelMix < 0.5 ? svmResult.margin.toFixed(2) : "\u2014"),
        ce("div", { style: { fontSize: 10, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Margin Width")
      ),
      ce("div", { style: { textAlign: "center" } },
        ce("div", { style: { fontSize: 18, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: textPrimary } }, kernelMix < 0.5 ? "Linear" : "RBF"),
        ce("div", { style: { fontSize: 10, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Kernel")
      ),
      ce("div", { style: { textAlign: "center" } },
        ce("div", { style: { fontSize: 18, fontFamily: "Georgia, serif", fontStyle: "italic", fontWeight: 700, color: textPrimary } }, "max w\u207B\xB9\u00B7\u2016margin\u2016"),
        ce("div", { style: { fontSize: 10, textTransform: "uppercase", letterSpacing: "0.15em", color: textMuted, fontFamily: "system-ui" } }, "Objective")
      )
    ),
    // Scaffolded steps panel - top right
    ce("div", {
      style: {
        position: "absolute", top: 16, right: 16, background: panelBg, backdropFilter: "blur(12px)",
        border: "1px solid " + panelBorder, borderRadius: 12, padding: 18, width: 300, pointerEvents: "auto"
      }
    },
      ce("div", { style: { fontSize: 10, textTransform: "uppercase", letterSpacing: "0.22em", color: textPrimary, fontFamily: "system-ui", fontWeight: 700, marginBottom: 8 } }, "Scaffolded Steps"),
      ce("div", { style: { fontSize: 11, color: textMuted, fontFamily: "system-ui", marginBottom: 12 } }, "Step " + (stepIndex + 1) + " / " + steps.length),
      ce("div", { style: { fontSize: 12, color: textPrimary, fontFamily: "system-ui", fontWeight: 700, marginBottom: 8, lineHeight: 1.5 } }, currentStep.instruction),
      ce("div", { style: { fontSize: 12, color: textMuted, fontFamily: "Georgia, serif", fontStyle: "italic", marginBottom: 12, lineHeight: 1.5 } }, currentStep.concept),
      ce("div", { style: { fontSize: 11, fontFamily: "ui-monospace, monospace", fontWeight: 700, color: conditionMet ? "#16A34A" : "#DC2626", marginBottom: 14 } }, conditionMet ? "\u2713 Condition met" : "\u2717 Condition not met"),
      ce("div", { style: { display: "flex", gap: 8, justifyContent: "center" } },
        ce("button", {
          style: {
            padding: "6px 14px", borderRadius: 6, border: "1px solid " + panelBorder, background: "transparent",
            color: textPrimary, fontSize: 11, textTransform: "uppercase", letterSpacing: "0.1em", cursor: "pointer", fontFamily: "system-ui",
            opacity: stepIndex <= 0 ? 0.3 : 1
          },
          disabled: stepIndex <= 0,
          onClick: function() { if (stepIndex > 0) runtimeState.params.stepIndex = stepIndex - 1; }
        }, "\u2190 Prev"),
        ce("button", {
          style: {
            padding: "6px 14px", borderRadius: 6, border: "1px solid " + panelBorder, background: "transparent",
            color: textPrimary, fontSize: 11, textTransform: "uppercase", letterSpacing: "0.1em", cursor: "pointer", fontFamily: "system-ui",
            opacity: stepIndex >= steps.length - 1 ? 0.3 : 1
          },
          disabled: stepIndex >= steps.length - 1,
          onClick: function() { if (stepIndex < steps.length - 1) runtimeState.params.stepIndex = stepIndex + 1; }
        }, "Next \u2192")
      )
    )
  );

  children.push(overlay);

  return ce("group", { ref: groupRef }, children);
}
return Scene;
